(function() {
    // 1. 配置参数：在这里修改你的图片链接和尺寸
    const config = {
        imgUrl: 'data:image/gif;base64,', // 替换成你的图片 URL
        size: '100px',           // 按钮宽度
        right: '10%',          // 距离右侧距离
        bottom: '30px',         // 距离底部距离
        showAt: 300             // 滚动多少像素后显示
    };

    // 2. 创建 HTML 元素
    const bttBtn = document.createElement('div');
    bttBtn.id = 'custom-back-to-top';
    bttBtn.innerHTML = `<img src="${config.imgUrl}" alt="Top" style="width:100%; display:block;">`;
    document.body.appendChild(bttBtn);

    // 3. 注入 CSS 样式
    const style = document.createElement('style');
    style.textContent = `
        #custom-back-to-top {
            position: fixed;
            right: ${config.right};
            bottom: ${config.bottom};
            width: ${config.size};
            cursor: pointer;
            z-index: 10000;
            opacity: 0;
            visibility: hidden;
            transition: all 0.3s ease-in-out;
            transform: translateY(20px);
        }
        #custom-back-to-top.is-visible {
            opacity: 1;
            visibility: visible;
            transform: translateY(0);
        }
        #custom-back-to-top:hover {
            transform: scale(1.1);
        }
    `;
    document.head.appendChild(style);

    // 4. 滚动逻辑
    const handleScroll = () => {
        if (window.pageYOffset > config.showAt) {
            bttBtn.classList.add('is-visible');
        } else {
            bttBtn.classList.remove('is-visible');
        }
    };

    // 5. 点击回顶逻辑
    const scrollToTop = () => {
        window.scrollTo({
            top: 0,
            behavior: 'smooth'
        });
    };

    // 绑定事件
    window.addEventListener('scroll', handleScroll);
    bttBtn.addEventListener('click', scrollToTop);

    // 如果你的博客用了 PJAX，确保在页面切换后依然能正常工作
    document.addEventListener('pjax:complete', () => {
        // 重新检查是否需要显示
        handleScroll();
    });
})();